import Balancer from 'react-wrap-balancer'

import type { CtaProps } from '../../shared/cta/cta'
import { Cta } from '../../shared/cta/cta'

export interface HeroHeadlinePreviewProps {
  title: string
  description: string
  media: {
    src: string
    alt: string
  }
  cta?: CtaProps
}

export function HeroHeadlinePreview({
  title,
  description,
  media,
  cta,
}: Readonly<HeroHeadlinePreviewProps>) {
  return (
    <div className="flex flex-col gap-12 md:gap-16">
      <div className="mx-auto flex max-w-3xl flex-col items-center gap-6 text-center">
        <div className="flex flex-col gap-4">
          {title && (
            <h1 className="text-2xl font-semibold tracking-tight text-balance md:text-3xl">
              <Balancer balance={0.5}>{title}</Balancer>
            </h1>
          )}
          {description && (
            <p className="text-muted-foreground text-sm leading-7 md:text-base">
              <Balancer balance={0.5}>{description}</Balancer>
            </p>
          )}
        </div>

        {cta && <Cta cta={cta} />}
      </div>

      {media && (
        <div className="relative">
          <div className="overflow-hidden rounded-2xl">
            <img
              src={media.src}
              alt={media.alt ?? title ?? 'Hero preview'}
              loading="lazy"
              decoding="async"
              className="h-100 w-full object-cover"
            />
          </div>
          <div className="from-background via-background/80 pointer-events-none absolute inset-x-0 bottom-0 h-32 bg-linear-to-t to-transparent md:h-32" />
        </div>
      )}
    </div>
  )
}

import {
  HeroHeadlinePreview,
  type HeroHeadlinePreviewProps,
} from './hero-headline-preview'

export const values = {
  title: 'New UI blocks, ready for your next launch',
  description:
    'Explore a cleaner, sharper presentation for your next section. A focused headline, a direct CTA, and a strong visual below to anchor the page.',
  media: {
    src: 'https://images.unsplash.com/photo-1750449316808-31a9a800a84b?q=80&w=1219&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D',
    alt: 'Preview of a UI block with content and media',
  },
  cta: {
    ctaEnabled: true,
    text: 'Explore Blocks',
    link: '/blocks',
    variant: 'default',
    size: 'lg',
  },
} satisfies HeroHeadlinePreviewProps

export function HeroHeadlinePreviewExample() {
  return (
    <HeroHeadlinePreview
      title={values.title}
      description={values.description}
      media={values.media}
      cta={values.cta}
    />
  )
}
